-- ==========================================================================
-- 更新 biz_performance_year 表的 target_value
-- 根据关联任务的目标值和数据类型进行聚合计算
-- ==========================================================================

-- 开启事务，确保数据一致性
START TRANSACTION;

-- 1. 先备份原始数据（可选，建议先执行）
-- CREATE TABLE biz_performance_year_backup_20260307 AS SELECT * FROM biz_performance_year;

-- 2. 更新 target_value
-- 使用子查询计算每个绩效指标每年的目标值
UPDATE biz_performance_year py
    INNER JOIN (
    SELECT
    rtp.perf_id,
    py2.year,
    -- 根据数据类型进行不同的聚合
    CASE p.data_type
    WHEN '1' THEN COALESCE(SUM(t.target_value), 0)  -- 数值累加
    WHEN '2' THEN COALESCE(MAX(t.target_value), 0)  -- 百分比取大
    ELSE p.target_value  -- 类型0：使用绩效指标本身的目标值
    END AS calculated_target
    FROM rel_task_performance rtp
    INNER JOIN biz_performance_year py2 ON rtp.year_id = py2.year_id
    INNER JOIN biz_performance p ON rtp.perf_id = p.perf_id
    INNER JOIN biz_task t ON rtp.task_id = t.task_id
    WHERE t.is_delete = 0  -- 只统计未删除的任务
    GROUP BY rtp.perf_id, py2.year, p.data_type, p.target_value
    ) AS calc ON py.perf_id = calc.perf_id AND py.year = calc.year
    SET py.target_value = calc.calculated_target
WHERE py.is_delete = 0;  -- 只更新未删除的年度记录

UPDATE `biz_performance`
SET `data_type` = '2',
    `target_value` = 100.0000,
    `update_time` = CURRENT_TIMESTAMP
WHERE `perf_id` BETWEEN 153 AND 162;

-- 3. 特殊处理：对于类型0的指标，如果没有关联任务，保持原值
-- 但通常类型0的指标已经在上面被正确处理了

-- 4. 提交事务
COMMIT;

-- 5. 验证更新结果
-- 查看更新后的数据
SELECT
    p.perf_id,
    p.perf_code,
    p.perf_name,
    p.data_type,
    py.year,
    py.target_value,
    p.target_value AS perf_total_target
FROM biz_performance_year py
         INNER JOIN biz_performance p ON py.perf_id = p.perf_id
ORDER BY p.perf_id, py.year;

SET FOREIGN_KEY_CHECKS = 1;

-- TASK_ID_COMPAT_FIX_BEGIN
-- Compatibility fix for rel_task_performance only. It rewrites legacy task ids
-- to current biz_task.task_id by task_code. ???????????
DROP TEMPORARY TABLE IF EXISTS __legacy_task_id_map;
CREATE TEMPORARY TABLE __legacy_task_id_map (
  legacy_task_id BIGINT NOT NULL PRIMARY KEY,
  task_code VARCHAR(32) NOT NULL UNIQUE
);



DROP TEMPORARY TABLE IF EXISTS __rel_task_performance_fix;
CREATE TEMPORARY TABLE __rel_task_performance_fix AS
SELECT
  r.id AS old_rel_id,
  t.task_id AS fixed_task_id,
  r.perf_id,
  r.year_id,
  r.weight,
  r.contribution_value,
  r.data_type
FROM rel_task_performance r
JOIN __legacy_task_id_map m ON m.legacy_task_id = r.task_id
JOIN biz_task t ON t.task_code = m.task_code AND t.level = 3 AND t.is_delete = 0
WHERE r.task_id <> t.task_id;

SELECT COUNT(*) AS performance_rows_to_fix FROM __rel_task_performance_fix;

DELETE r
FROM rel_task_performance r
JOIN __rel_task_performance_fix f ON f.old_rel_id = r.id;

SELECT fixed_task_id, perf_id, year_id, weight, contribution_value, data_type
FROM __rel_task_performance_fix
ON DUPLICATE KEY UPDATE
  weight = VALUES(weight),
  contribution_value = VALUES(contribution_value),
  data_type = VALUES(data_type);

DROP TEMPORARY TABLE IF EXISTS __rel_task_performance_fix;
DROP TEMPORARY TABLE IF EXISTS __legacy_task_id_map;
-- TASK_ID_COMPAT_FIX_END
